import subprocess

# Try systemctl first
result = subprocess.run(['systemctl', 'start', 'sshd'], capture_output=True)
if result.returncode == 0:
    out1 = "✅ SSH started with systemctl"
else:
    # Try service command
    result = subprocess.run(['service', 'ssh', 'start'], capture_output=True)
    if result.returncode == 0:
        out1 = "✅ SSH started with service"
    else:
        out1 = "❌ Failed to start SSH. Is it installed?"
